SET @has_old_chat_role := (SELECT COUNT(*) FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'chatMessages' AND COLUMN_NAME = 'chatMessageRole');
SET @has_new_chat_role := (SELECT COUNT(*) FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'chatMessages' AND COLUMN_NAME = 'role');
SET @chat_role_sql := IF(@has_old_chat_role = 1 AND @has_new_chat_role = 0, 'ALTER TABLE `chatMessages` RENAME COLUMN `chatMessageRole` TO `role`', 'SELECT ''chatMessages role column already aligned'' AS status');
PREPARE chat_role_stmt FROM @chat_role_sql;
EXECUTE chat_role_stmt;
DEALLOCATE PREPARE chat_role_stmt;

